const webhook = $node['Webhook: LP Deploy'].json.body;
const project = $node['Fetch Vercel Project'].json[0] || {};
const generation = $node['Fetch Generation'].json[0] || {};
const existingPages = $node['Fetch Existing Live Pages'].json || [];
const pixels = project.tracking_pixels || {};

// Inject tracking pixels into HTML
function injectPixels(html) {
  let result = html;

  // Build head tracking code
  let headCode = '';
  if (pixels.fb_pixel_id) {
    headCode += `\n<!-- Facebook Pixel -->\n<script>\n!function(f,b,e,v,n,t,s){if(f.fbq)return;n=f.fbq=function(){n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}(window,document,'script','https://connect.facebook.net/en_US/fbevents.js');\nfbq('init','${pixels.fb_pixel_id}');\nfbq('track','PageView');\n</script>\n<noscript><img height="1" width="1" style="display:none" src="https://www.facebook.com/tr?id=${pixels.fb_pixel_id}&ev=PageView&noscript=1"/></noscript>`;
  }
  if (pixels.gtm_id) {
    headCode += `\n<!-- Google Tag Manager -->\n<script>(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({'gtm.start':new Date().getTime(),event:'gtm.js'});var f=d.getElementsByTagName(s)[0],j=d.createElement(s),dl=l!='dataLayer'?'&l='+l:'';j.async=true;j.src='https://www.googletagmanager.com/gtm.js?id='+i+dl;f.parentNode.insertBefore(j,f);})(window,document,'script','dataLayer','${pixels.gtm_id}');</script>`;
  }
  if (pixels.custom_head) {
    headCode += '\n' + pixels.custom_head;
  }

  // Build body tracking code
  let bodyCode = '';
  if (pixels.gtm_id) {
    bodyCode += `\n<!-- Google Tag Manager (noscript) -->\n<noscript><iframe src="https://www.googletagmanager.com/ns.html?id=${pixels.gtm_id}" height="0" width="0" style="display:none;visibility:hidden"></iframe></noscript>`;
  }
  if (pixels.hyros_script) {
    bodyCode += '\n<!-- Hyros -->\n' + pixels.hyros_script;
  }
  if (pixels.custom_body) {
    bodyCode += '\n' + pixels.custom_body;
  }

  // Replace placeholders or inject before closing tags
  if (result.includes('<!-- TRACKING_HEAD -->')) {
    result = result.replace('<!-- TRACKING_HEAD -->', headCode);
  } else {
    result = result.replace('</head>', headCode + '\n</head>');
  }

  if (result.includes('<!-- TRACKING_BODY -->')) {
    result = result.replace('<!-- TRACKING_BODY -->', bodyCode);
  } else {
    result = result.replace('</body>', bodyCode + '\n</body>');
  }

  return result;
}

// Build files object for Vercel Files API
// Include all existing live pages + the new page
const files = [];

// Add existing live pages
for (const page of existingPages) {
  if (page.route === webhook.route) continue; // Skip if we're replacing same route
  const route = page.route.startsWith('/') ? page.route : '/' + page.route;
  files.push({
    file: route === '/' ? 'index.html' : route.slice(1) + '/index.html',
    data: page.html_content
  });
}

// Add the new page with pixels injected
const newHtml = injectPixels(generation.html_content || '<html><body>No content</body></html>');
const newRoute = webhook.route.startsWith('/') ? webhook.route : '/' + webhook.route;
files.push({
  file: newRoute === '/' ? 'index.html' : newRoute.slice(1) + '/index.html',
  data: newHtml
});

return [{
  json: {
    vercel_project_id: project.vercel_project_id,
    vercel_token: project.vercel_token,
    project_name: project.project_name,
    team_id: project.team_id,
    files: files,
    newPageHtml: newHtml,
    route: webhook.route,
    variant_label: webhook.variant_label,
    variant_group: webhook.variant_group,
    generation_id: webhook.generation_id,
    db_project_id: webhook.vercel_project_id,
    default_domain: project.default_domain
  }
}];

const deployResult = $input.first().json;
const buildData = $node['Build Deployment Files'].json;

const deploymentUrl = deployResult.url || deployResult.alias?.[0] || `${buildData.default_domain}${buildData.route}`;

return [{
  json: {
    generation_id: buildData.generation_id,
    vercel_project_id: buildData.db_project_id,
    route: buildData.route,
    html_content: buildData.newPageHtml,
    variant_label: buildData.variant_label || null,
    variant_group: buildData.variant_group || null,
    deployment_url: deploymentUrl.startsWith('http') ? deploymentUrl : 'https://' + deploymentUrl,
    deployment_id: deployResult.id || null,
    is_live: true
  }
}];
